const fs = require('fs');
const REGISTRY_PATH = '/data/shared/templates/registry.json';

let registry;
try {
  registry = JSON.parse(fs.readFileSync(REGISTRY_PATH, 'utf8'));
} catch (err) {
  return [{
    json: {
      success: false,
      error: `Kon registry niet lezen: ${err.message}`,
      banks: []
    }
  }];
}

const banks = Object.entries(registry.banks || {}).map(([bankId, b]) => {
  const templateFilename = b.template_filename || null;
  const templatePath = templateFilename
    ? `/data/shared/templates/${bankId}/${templateFilename}`
    : null;
  let fileExists = false;
  let fileSize = null;
  let fileMtime = null;
  if (templatePath) {
    try {
      const stat = fs.statSync(templatePath);
      fileExists = true;
      fileSize = stat.size;
      fileMtime = stat.mtime.toISOString();
    } catch {
      fileExists = false;
    }
  }
  return {
    bank_id: bankId,
    display_name: b.display_name || bankId,
    keywords: b.keywords || [],
    template_filename: templateFilename,
    uploaded_at: b.uploaded_at || null,
    uploaded_by: b.uploaded_by || null,
    file_exists: fileExists,
    file_size: fileSize,
    file_mtime: fileMtime,
    placeholder_count: Object.keys(b.placeholders || {}).length
  };
});

return [{
  json: {
    success: true,
    schema_version: registry.schema_version || 1,
    banks
  }
}];

const fs = require('fs');
const path = require('path');
const REGISTRY_PATH = '/data/shared/templates/registry.json';
const TEMPLATES_DIR = '/data/shared/templates';

// Verwacht multipart-form-data: bank_id (text field) + file (binary, .docx)
const body = $json.body || $json || {};
const bankId = String(body.bank_id || '').trim();
const uploadedBy = String(body.uploaded_by || 'webapp').trim() || 'webapp';

if (!bankId) {
  throw new Error('Veld \'bank_id\' ontbreekt in form data.');
}
if (!/^[a-z0-9_-]+$/i.test(bankId)) {
  throw new Error(`Ongeldig bank_id: '${bankId}'. Alleen letters/cijfers/-/_ toegestaan.`);
}

const binaries = $binary || {};
const binKeys = Object.keys(binaries);
let binEntry = binaries.file || binaries.template || (binKeys.length === 1 ? binaries[binKeys[0]] : null);
if (!binEntry) {
  for (const k of binKeys) {
    const fn = String(binaries[k]?.fileName || '').toLowerCase();
    if (fn.endsWith('.docx')) { binEntry = binaries[k]; break; }
  }
}
if (!binEntry) {
  throw new Error(
    `Geen .docx-bestand gevonden in upload. Binary keys: ${binKeys.join(', ') || '(geen)'}.`
  );
}

const originalName = String(binEntry.fileName || 'template.docx');
if (!originalName.toLowerCase().endsWith('.docx')) {
  throw new Error(`Alleen .docx-bestanden zijn toegestaan. Ontvangen: ${originalName}`);
}

// Sanitize filename — voorkom path traversal.
const safeName = path.basename(originalName).replace(/[^A-Za-z0-9._-]/g, '_');
if (!safeName.toLowerCase().endsWith('.docx')) {
  throw new Error(`Bestandsnaam niet bruikbaar na sanitization: '${safeName}'`);
}

// Lees registry, valideer bank.
let registry;
try {
  registry = JSON.parse(fs.readFileSync(REGISTRY_PATH, 'utf8'));
} catch (err) {
  throw new Error(`Kon registry niet lezen: ${err.message}`);
}
const banks = registry.banks || {};
if (!banks[bankId]) {
  const known = Object.keys(banks).join(', ') || '(geen)';
  throw new Error(
    `Bank '${bankId}' is niet bekend in registry.json. ` +
    `Bekende banken: ${known}. Vraag een ontwikkelaar deze toe te voegen.`
  );
}

// Schrijf het bestand.
const targetDir = path.join(TEMPLATES_DIR, bankId);
fs.mkdirSync(targetDir, { recursive: true });
const targetPath = path.join(targetDir, safeName);

// In n8n is binEntry.data base64-gecodeerd.
let buffer;
if (binEntry.data) {
  buffer = Buffer.from(binEntry.data, 'base64');
} else if (binEntry.binaryData) {
  buffer = Buffer.from(binEntry.binaryData, 'base64');
} else {
  throw new Error('Binary entry bevat geen \'data\'-veld om te schrijven.');
}
fs.writeFileSync(targetPath, buffer);

// Update registry.
const now = new Date().toISOString();
banks[bankId].template_filename = safeName;
banks[bankId].uploaded_at = now;
banks[bankId].uploaded_by = uploadedBy;
fs.writeFileSync(REGISTRY_PATH, JSON.stringify(registry, null, 2) + '\n', 'utf8');

return [{
  json: {
    success: true,
    bank_id: bankId,
    display_name: banks[bankId].display_name || bankId,
    template_filename: safeName,
    template_path: targetPath,
    file_size: buffer.length,
    uploaded_at: now,
    uploaded_by: uploadedBy
  }
}];
